import torch
import torch.nn as nn


class EnergyBasedModel(nn.Module):
    """Simple EBM: scalar energy E_θ(x), score = -∇_x E_θ(x)."""

    def __init__(self, input_dim: int, hidden_dim: int = 256):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, 1),
        )

    def energy(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x).squeeze(-1)   # (B,)

    def score(self, x: torch.Tensor) -> torch.Tensor:
        """Score ∇_x log p = -∇_x E, computed via autograd."""
        x = x.requires_grad_(True)
        e = self.energy(x).sum()         # scalar for backward
        grad = torch.autograd.grad(e, x)[0]
        return -grad                     # (B, D)


class ScoreNetwork(nn.Module):
    """Direct score network s_θ(x) ≈ ∇_x log p(x), no energy formulation."""

    def __init__(self, input_dim: int, hidden_dim: int = 256):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, input_dim),   # output shape matches x
        )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x)   # (B, D) — same shape as x

import torch
import torch.nn as nn

class NCSNScore(nn.Module):
    """
    Noise Conditional Score Network (NCSNv2 style).
    Network predicts score s_θ(x, σ) normalized by σ.
    """
    def __init__(self, input_dim: int, hidden: int = 256, n_sigma: int = 10):
        super().__init__()
        # σ embedding: learned lookup table over discrete noise levels
        self.sigma_embed = nn.Embedding(n_sigma, hidden)
        self.net = nn.Sequential(
            nn.Linear(input_dim + hidden, hidden), nn.SiLU(),
            nn.Linear(hidden, hidden), nn.SiLU(),
            nn.Linear(hidden, input_dim),
        )

    def forward(self, x: torch.Tensor, sigma_idx: torch.Tensor) -> torch.Tensor:
        """
        x: (B, D)  noisy input
        sigma_idx: (B,) int indices into sigma schedule
        Returns: score estimate (B, D) = ∇_x log p_σ(x)
        """
        emb = self.sigma_embed(sigma_idx)          # (B, hidden)
        inp = torch.cat([x, emb], dim=-1)           # (B, D + hidden)
        return self.net(inp)                        # (B, D)


class EMAModel:
    """Exponential moving average of model weights for stable sampling."""
    def __init__(self, model: nn.Module, decay: float = 0.9999):
        self.shadow = {k: v.clone().detach() for k, v in model.named_parameters()}
        self.decay = decay

    @torch.no_grad()
    def update(self, model: nn.Module):
        for name, param in model.named_parameters():
            self.shadow[name].mul_(self.decay).add_(param.data, alpha=1 - self.decay)

    def copy_to(self, model: nn.Module):
        for name, param in model.named_parameters():
            param.data.copy_(self.shadow[name])
